# tests/evals/conftest.py
"""Custom pytest plugin: collect pass/fail rates and enforce threshold."""
import pytest

_results = []

def pytest_runtest_logreport(report):
    if report.when == "call":
        _results.append(report.passed)

def pytest_sessionfinish(session, exitstatus):
    threshold = float(session.config.getoption("--eval-threshold", default=0.85))
    if not _results:
        return
    pass_rate = sum(_results) / len(_results)
    print(f"\nEval pass rate: {pass_rate:.1%} (threshold: {threshold:.1%})")
    if pass_rate < threshold:
        session.exitstatus = 1
        print(f"EVAL GATE FAILED: {pass_rate:.1%} < {threshold:.1%}")

def pytest_addoption(parser):
    parser.addoption("--eval-threshold", default="0.85")

