"""Load versioned prompts from disk. Path: prompts/<env>/<name>.txt"""
import hashlib, pathlib

PROMPT_DIR = pathlib.Path(__file__).parent

def load_prompt(name: str, env: str = "production") -> str:
    path = PROMPT_DIR / env / f"{name}.txt"
    if not path.exists():
        path = PROMPT_DIR / f"{name}.txt"   # fall back to base
    return path.read_text().strip()

def prompt_hash(name: str, env: str = "production") -> str:
    """Return a short content hash for deployment manifests."""
    content = load_prompt(name, env)
    return hashlib.sha256(content.encode()).hexdigest()[:12]
